using Microsoft.ML.Data;

namespace ChurnPredictor.Models;

public class CustomerData
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    public string Churned { get; set; } = string.Empty;
}

using Microsoft.ML.Data;

namespace ChurnPredictor.Models;

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

using Microsoft.ML;
using Microsoft.ML.Data;
using ChurnPredictor.Models;

namespace ChurnPredictor.Services;

public class ChurnModelService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly IDataView _dataView;
    private readonly string _dataPath;

    public ChurnModelService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "customers.csv");

        _dataView = _mlContext.Data.LoadFromTextFile<CustomerData>(
            _dataPath, hasHeader: true, separatorChar: ',');

        var pipeline = _mlContext.Transforms.CustomMapping<CustomerData, LabelOutput>(
                (input, output) => { output.Label = input.Churned == "Yes"; },
                contractName: "ChurnToLabel")
            .Append(_mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                nameof(CustomerData.Age),
                nameof(CustomerData.Income),
                nameof(CustomerData.PurchaseHistory),
                "RegionEncoded"))
            .Append(_mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
                labelColumnName: "Label", featureColumnName: "Features"));

        _model = pipeline.Fit(_dataView);
    }

    public ChurnPrediction Predict(CustomerData customer)
    {
        var predictionEngine = _mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(_model);
        return predictionEngine.Predict(customer);
    }

    public object Evaluate()
    {
        var predictions = _model.Transform(_dataView);
        var metrics = _mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

        return new
        {
            Accuracy = metrics.Accuracy,
            AUC = metrics.AreaUnderRocCurve,
            F1Score = metrics.F1Score
        };
    }

    // Helper class for the custom mapping output
    public class LabelOutput
    {
        public bool Label { get; set; }
    }
}

