using ChurnPredictor.Models;
using ChurnPredictor.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddSingleton<ChurnModelService>();

var app = builder.Build();

// Eagerly initialize the model at startup
app.Services.GetRequiredService<ChurnModelService>();

app.MapGet("/", () => "Welcome to the Churn Prediction API. " +
    "POST /predict with { age, income, region, purchaseHistory } to predict churn. " +
    "GET /metrics to view model evaluation metrics.");

app.MapPost("/predict", (PredictRequest request, ChurnModelService service) =>
{
    var customer = new CustomerData
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region ?? string.Empty,
        PurchaseHistory = request.PurchaseHistory
    };

    var prediction = service.Predict(customer);

    return Results.Json(new
    {
        predictedChurn = prediction.PredictedLabel,
        probability = prediction.Probability
    });
});

app.MapGet("/metrics", (ChurnModelService service) =>
{
    return Results.Json(service.Evaluate());
});

app.Run();

public record PredictRequest(float Age, float Income, string? Region, float PurchaseHistory);

